const { DynamoDBClient } = require('@aws-sdk/client-dynamodb');
const { DynamoDBDocumentClient, UpdateCommand, GetCommand } = require('@aws-sdk/lib-dynamodb');
const https = require('https');
const { URL } = require('url');

// Initialize clients outside handler for connection reuse
const dynamoClient = new DynamoDBClient({});
const docClient = DynamoDBDocumentClient.from(dynamoClient);

const TABLE_NAME = process.env.ORDERS_TABLE_NAME;
const PAYMENT_API_BASE_URL = process.env.PAYMENT_API_BASE_URL;
const PAYMENT_API_KEY_PARAM = process.env.PAYMENT_API_KEY_SSM_PARAM;

// Cache for secrets to avoid repeated SSM calls within the same Lambda instance
let cachedApiKey = null;
let cacheExpiry = 0;

const { SSMClient, GetParameterCommand } = require('@aws-sdk/client-ssm');
const ssmClient = new SSMClient({});

// Allowlisted order statuses
const VALID_ORDER_STATUSES = new Set(['pending', 'processing', 'completed', 'failed', 'refunded']);

// Allowlisted currency codes (ISO 4217)
const VALID_CURRENCIES = new Set(['USD', 'EUR', 'GBP', 'CAD', 'AUD', 'JPY']);

// Maximum allowed amount
const MAX_ORDER_AMOUNT = 1000000;

async function getPaymentApiKey() {
    const now = Date.now();
    if (cachedApiKey && now < cacheExpiry) {
        return cachedApiKey;
    }

    const command = new GetParameterCommand({
        Name: PAYMENT_API_KEY_PARAM,
        WithDecryption: true,
    });

    const response = await ssmClient.send(command);
    cachedApiKey = response.Parameter.Value;
    // Cache for 5 minutes
    cacheExpiry = now + 5 * 60 * 1000;
    return cachedApiKey;
}

function validateOrderId(orderId) {
    if (typeof orderId !== 'string') return false;
    // Allow only alphanumeric, hyphens, and underscores; max 64 chars
    return /^[a-zA-Z0-9_-]{1,64}$/.test(orderId);
}

function validateAmount(amount) {
    if (typeof amount !== 'number') return false;
    if (!Number.isFinite(amount)) return false;
    if (amount <= 0 || amount > MAX_ORDER_AMOUNT) return false;
    // Ensure at most 2 decimal places
    if (Math.round(amount * 100) !== amount * 100) return false;
    return true;
}

function validateCurrency(currency) {
    if (typeof currency !== 'string') return false;
    return VALID_CURRENCIES.has(currency);
}

function validateCustomerId(customerId) {
    if (typeof customerId !== 'string') return false;
    return /^[a-zA-Z0-9_-]{1,64}$/.test(customerId);
}

function validatePaymentMethod(paymentMethod) {
    if (typeof paymentMethod !== 'string') return false;
    const allowedMethods = new Set(['credit_card', 'debit_card', 'bank_transfer', 'digital_wallet']);
    return allowedMethods.has(paymentMethod);
}

function sanitizeForLogging(obj) {
    if (!obj) return obj;
    const sanitized = { ...obj };
    // Remove or mask sensitive fields before logging
    const sensitiveFields = ['cardNumber', 'cvv', 'ssn', 'password', 'token', 'apiKey', 'authorization', 'paymentToken'];
    for (const field of sensitiveFields) {
        if (sanitized[field]) {
            sanitized[field] = '[REDACTED]';
        }
    }
    if (sanitized.email && typeof sanitized.email === 'string') {
        const parts = sanitized.email.split('@');
        if (parts.length === 2) {
            sanitized.email = parts[0].substring(0, 2) + '***@' + parts[1];
        }
    }
    return sanitized;
}

function parseAndValidateOrder(messageBody) {
    let order;
    try {
        order = JSON.parse(messageBody);
    } catch {
        throw new Error('Invalid JSON in message body');
    }

    if (!order || typeof order !== 'object' || Array.isArray(order)) {
        throw new Error('Order must be a non-null object');
    }

    const { orderId, customerId, amount, currency, paymentMethod } = order;

    if (!validateOrderId(orderId)) {
        throw new Error('Invalid orderId format');
    }

    if (!validateCustomerId(customerId)) {
        throw new Error('Invalid customerId format');
    }

    if (!validateAmount(amount)) {
        throw new Error('Invalid amount');
    }

    if (!validateCurrency(currency)) {
        throw new Error('Invalid currency');
    }

    if (!validatePaymentMethod(paymentMethod)) {
        throw new Error('Invalid payment method');
    }

    // Return only validated and expected fields (allowlist approach)
    return {
        orderId,
        customerId,
        amount,
        currency,
        paymentMethod,
    };
}

async function callPaymentApi(order, apiKey) {
    // Validate the base URL is an allowed HTTPS endpoint
    const parsedUrl = new URL('/v1/charges', PAYMENT_API_BASE_URL);

    if (parsedUrl.protocol !== 'https:') {
        throw new Error('Payment API must use HTTPS');
    }

    // Allowlist of permitted payment API hostnames
    const allowedHosts = process.env.ALLOWED_PAYMENT_HOSTS
        ? process.env.ALLOWED_PAYMENT_HOSTS.split(',').map(h => h.trim())
        : [];

    if (allowedHosts.length > 0 && !allowedHosts.includes(parsedUrl.hostname)) {
        throw new Error('Payment API hostname not in allowlist');
    }

    const payload = JSON.stringify({
        orderId: order.orderId,
        amount: order.amount,
        currency: order.currency,
        paymentMethod: order.paymentMethod,
        customerId: order.customerId,
        idempotencyKey: `order-${order.orderId}`,
    });

    return new Promise((resolve, reject) => {
        const options = {
            hostname: parsedUrl.hostname,
            port: parsedUrl.port || 443,
            path: parsedUrl.pathname,
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Content-Length': Buffer.byteLength(payload),
                'Authorization': `Bearer ${apiKey}`,
                'Idempotency-Key': `order-${order.orderId}`,
            },
            timeout: 10000,
            // Enforce TLS 1.2+
            minVersion: 'TLSv1.2',
        };

        const req = https.request(options, (res) => {
            let data = '';
            const maxResponseSize = 1024 * 1024; // 1MB limit

            res.on('data', (chunk) => {
                data += chunk;
                if (data.length > maxResponseSize) {
                    req.destroy(new Error('Response too large'));
                }
            });

            res.on('end', () => {
                try {
                    const response = JSON.parse(data);

                    if (res.statusCode >= 200 && res.statusCode < 300) {
                        // Validate expected response fields
                        if (response.transactionId && typeof response.transactionId === 'string') {
                            resolve({
                                success: true,
                                transactionId: response.transactionId.substring(0, 128),
                                status: response.status === 'approved' ? 'approved' : 'declined',
                            });
                        } else {
                            reject(new Error('Invalid payment API response structure'));
                        }
                    } else if (res.statusCode === 402) {
                        resolve({
                            success: false,
                            status: 'declined',
                            reason: typeof response.reason === 'string'
                                ? response.reason.substring(0, 256)
                                : 'unknown',
                        });
                    } else {
                        reject(new Error(`Payment API returned status ${res.statusCode}`));
                    }
                } catch {
                    reject(new Error('Failed to parse payment API response'));
                }
            });
        });

        req.on('error', (err) => {
            reject(new Error(`Payment API request failed: ${err.message}`));
        });

        req.on('timeout', () => {
            req.destroy(new Error('Payment API request timed out'));
        });

        req.write(payload);
        req.end();
    });
}

async function updateOrderInDynamo(orderId, status, transactionId, reason) {
    if (!VALID_ORDER_STATUSES.has(status)) {
        throw new Error('Invalid status for DynamoDB update');
    }

    const now = new Date().toISOString();

    const updateExpression = transactionId
        ? 'SET orderStatus = :status, transactionId = :txnId, updatedAt = :now'
        : 'SET orderStatus = :status, failureReason = :reason, updatedAt = :now';

    const expressionValues = transactionId
        ? {
            ':status': status,
            ':txnId': transactionId,
            ':now': now,
            ':expectedStatus': 'pending',
        }
        : {
            ':status': status,
            ':reason': reason || 'unknown',
            ':now': now,
            ':expectedStatus': 'pending',
        };

    const command = new UpdateCommand({
        TableName: TABLE_NAME,
        Key: { orderId },
        UpdateExpression: updateExpression,
        // Conditional update to prevent processing already-processed orders
        ConditionExpression: 'orderStatus = :expectedStatus',
        ExpressionAttributeValues: expressionValues,
        ReturnValues: 'NONE',
    });

    await docClient.send(command);
}

async function processOrder(order, apiKey) {
    // Update status to processing first
    await updateOrderInDynamo(order.orderId, 'processing', null, null);

    const paymentResult = await callPaymentApi(order, apiKey);

    if (paymentResult.success) {
        // For the completed update, we need to handle the condition differently
        // since status is now 'processing' not 'pending'
        const command = new UpdateCommand({
            TableName: TABLE_NAME,
            Key: { orderId: order.orderId },
            UpdateExpression: 'SET orderStatus = :status, transactionId = :txnId, updatedAt = :now',
            ConditionExpression: 'orderStatus = :expectedStatus',
            ExpressionAttributeValues: {
                ':status': 'completed',
                ':txnId': paymentResult.transactionId,
                ':now': new Date().toISOString(),
                ':expectedStatus': 'processing',
            },
            ReturnValues: 'NONE',
        });
        await docClient.send(command);

        console.log(JSON.stringify({
            level: 'INFO',
            message: 'Order processed successfully',
            orderId: order.orderId,
            // Do not log transactionId or sensitive payment details
        }));
    } else {
        const command = new UpdateCommand({
            TableName: TABLE_NAME,
            Key: { orderId: order.orderId },
            UpdateExpression: 'SET orderStatus = :status, failureReason = :reason, updatedAt = :now',
            ConditionExpression: 'orderStatus = :expectedStatus',
            ExpressionAttributeValues: {
                ':status': 'failed',
                ':reason': paymentResult.reason || 'declined',
                ':now': new Date().toISOString(),
                ':expectedStatus': 'processing',
            },
            ReturnValues: 'NONE',
        });
        await docClient.send(command);

        console.log(JSON.stringify({
            level: 'WARN',
            message: 'Payment declined',
            orderId: order.orderId,
            reason: paymentResult.reason,
        }));
    }
}

exports.handler = async (event) => {
    if (!TABLE_NAME || !PAYMENT_API_BASE_URL || !PAYMENT_API_KEY_PARAM) {
        console.log(JSON.stringify({
            level: 'ERROR',
            message: 'Missing required environment variables',
        }));
        throw new Error('Missing required environment variables');
    }

    // Retrieve API key from SSM Parameter Store (encrypted)
    let apiKey;
    try {
        apiKey = await getPaymentApiKey();
    } catch (err) {
        console.log(JSON.stringify({
            level: 'ERROR',
            message: 'Failed to retrieve payment API key from SSM',
            error: err.message,
        }));
        // Throw to retry all messages
        throw new Error('Failed to retrieve payment API key');
    }

    // Track failed message IDs for partial batch response
    const batchItemFailures = [];

    if (!event.Records || !Array.isArray(event.Records)) {
        console.log(JSON.stringify({
            level: 'ERROR',
            message: 'Invalid event structure - no Records array',
        }));
        return { batchItemFailures: [] };
    }

    for (const record of event.Records) {
        const messageId = record.messageId;

        try {
            if (!record.body || typeof record.body !== 'string') {
                console.log(JSON.stringify({
                    level: 'ERROR',
                    message: 'Empty or invalid message body',
                    messageId,
                }));
                // Don't retry malformed messages
                continue;
            }

            const order = parseAndValidateOrder(record.body);

            console.log(JSON.stringify({
                level: 'INFO',
                message: 'Processing order',
                orderId: order.orderId,
                messageId,
            }));

            await processOrder(order, apiKey);

        } catch (err) {
            // Check if this is a validation error (don't retry) vs transient error (retry)
            const isValidationError = err.message.startsWith('Invalid') ||
                err.message === 'Order must be a non-null object' ||
                err.message === 'Invalid JSON in message body';

            const isConditionalCheckFailed = err.name === 'ConditionalCheckFailedException';

            if (isValidationError) {
                // Log validation errors but don't retry - message is malformed
                console.log(JSON.stringify({
                    level: 'ERROR',
                    message: 'Order validation failed - skipping',
                    messageId,
                    error: err.message,
                    // Don't log the raw body as it may contain sensitive data
                }));
            } else if (isConditionalCheckFailed) {
                // Order already processed (idempotency protection)
                console.log(JSON.stringify({
                    level: 'WARN',
                    message: 'Order already processed or in unexpected state - skipping',
                    messageId,
                }));
            } else {
                // Transient error - report as failure for retry
                console.log(JSON.stringify({
                    level: 'ERROR',
                    message: 'Transient error processing order - will retry',
                    messageId,
                    error: err.message,
                }));

                batchItemFailures.push({
                    itemIdentifier: messageId,
                });
            }
        }
    }

    // Return partial batch failure response so SQS only retries failed messages
    return { batchItemFailures };
};